def generate_all_data():
    """Generate all training data files."""
    raw_dir = Path("data/raw")
    raw_dir.mkdir(parents=True, exist_ok=True)

    total_generated = 0

    for category, examples in TRAINING_DATA.items():
        if not examples:  # Skip empty categories
            continue
        
        output_file = raw_dir / f"{category}_examples.jsonl"

        with open(output_file, "w") as f:
            for example in examples:
                entry = {
                    "messages": [
                        {"role": "system", "content": SYSTEM_PROMPT},
                        {"role": "user", "content": example["prompt"]},
                        {"role": "assistant", "content": example["answer"]}
                    ]
                }
                f.write(json.dumps(entry) + "\n")
                total_generated += 1

        print(f"✅ Generated {len(examples)} {category} examples → {output_file}")

    print(f"\n{'='*60}")
    print(f"✅ Total Generated: {total_generated} high-quality examples")
    print(f"{'='*60}")
    print("\n🔄 Next steps:")
    print("   1. python merge_data.py         # Merge data into train/val splits")
    print("   2. python train_unsloth.py      # Train the model")

if __name__ == "__main__":
    generate_all_data()
